import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";
import Navbar from "../components/Navbar";
import { toast } from "sonner";

export default function AdminLogin() {
  const nav = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      await adminLogin(email, password);
      toast.success("admin signed in");
      nav("/admin");
    } catch (err) {
      toast.error(err?.response?.data?.detail || "admin login failed");
    } finally {
      setBusy(false);
    }
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-md mx-auto px-6 pt-24 pb-16">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-white/10 text-xs mb-4 text-white/70 uppercase tracking-wider">
          restricted
        </div>
        <h1 className="hero-title text-5xl font-medium mb-2" data-testid="admin-login-title">admin login</h1>
        <p className="text-white/60 mb-8 text-sm">for spectral forge organisers only.</p>

        <form onSubmit={submit} className="space-y-3">
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="admin email"
            data-testid="admin-login-email-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <input
            type="password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="password"
            data-testid="admin-login-password-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <button
            type="submit"
            disabled={busy}
            data-testid="admin-login-submit-btn"
            className="w-full bg-white text-black rounded-full py-3 text-sm font-normal hover:bg-neutral-200 transition-colors disabled:opacity-50"
          >
            {busy ? "signing in..." : "sign in as admin"}
          </button>
        </form>
      </div>
    </div>
  );
}
